// ── Fallback sequences for tasks without explicit definitions ────────
// These are organized by keyword theme and used when a task ID doesn't
// have a direct entry in TASK_TOOL_SEQUENCES.

export const FALLBACK_SEQUENCES: ToolStep[][] = [
  [{ tool: "Read", target: "src/index.ts", action: "Reading file" }, { tool: "Grep", target: "handleRequest", action: "Searching codebase" }, { tool: "Read", target: "package.json", action: "Reading file" }, { tool: "Bash", target: "npm test", action: "Running command" }, { tool: "Glob", target: "src/**/*.ts", action: "Finding files" }],
  [{ tool: "Read", target: "tsconfig.json", action: "Reading file" }, { tool: "Grep", target: "export default", action: "Searching codebase" }, { tool: "Bash", target: "tsc --noEmit", action: "Running command" }, { tool: "Read", target: "src/utils/helpers.ts", action: "Reading file" }, { tool: "Grep", target: "TODO|FIXME", action: "Searching codebase" }],
  [{ tool: "Bash", target: "git log --oneline -5", action: "Running command" }, { tool: "Read", target: "src/config/index.ts", action: "Reading file" }, { tool: "Grep", target: "process\\.env", action: "Searching codebase" }, { tool: "Read", target: ".env.example", action: "Reading file" }, { tool: "Bash", target: "npm run lint", action: "Running command" }],
  [{ tool: "Glob", target: "src/**/*.{ts,tsx}", action: "Finding files" }, { tool: "Read", target: "src/app.ts", action: "Reading file" }, { tool: "Bash", target: "npm run build", action: "Running command" }, { tool: "Grep", target: "error|throw|catch", action: "Searching codebase" }, { tool: "Read", target: "README.md", action: "Reading file" }],
  [{ tool: "Read", target: "package-lock.json", action: "Reading file" }, { tool: "Bash", target: "npm outdated", action: "Running command" }, { tool: "Grep", target: "deprecated|legacy|TODO", action: "Searching codebase" }, { tool: "Glob", target: "src/**/index.ts", action: "Finding files" }, { tool: "Bash", target: "du -sh node_modules", action: "Running command" }],
];

/** Get all tool sequences for a given task ID, or fallback sequences. */
export function getSequencesForTask(taskId: string): ToolStep[][] {
  return TASK_TOOL_SEQUENCES[taskId] ?? FALLBACK_SEQUENCES;
}

/** Pick a single random sequence for a given task, or from all tasks if none specified. */
export function pickRandomSequence(taskId?: string | null): ToolStep[] {
  if (taskId) {
    const sequences = getSequencesForTask(taskId);
    return sequences[Math.floor(Math.random() * sequences.length)]!;
  }
  // No active task — pick from any task's sequences
  const allTaskIds = Object.keys(TASK_TOOL_SEQUENCES);
  const randomTaskId = allTaskIds[Math.floor(Math.random() * allTaskIds.length)]!;
  const sequences = TASK_TOOL_SEQUENCES[randomTaskId]!;
  return sequences[Math.floor(Math.random() * sequences.length)]!;
}
